102→const ThemeToggle = () => {
103→  const darkMode = useDarkMode(false, { global: globalThis.window })
104→  return (
105→    <Button
106→      round
107→      clear
108→      aria-label={`turn on ${darkMode.value ? 'light' : 'dark'} mode`}
109→      icon={darkMode.value ? 'moon' : 'sun'}
110→      onClick={darkMode.toggle}
111→    />
112→  )
113→}
