164→
165→  return (
166→    <Container
167→      className={className}
168→      data-testid="restaurant-card"
169→      onClick={isClosed ? undefined : onClick}
170→    >
171→      {isNew && <NewTag>new</NewTag>}
172→      <ImageContainer>
173→        {isClosed && (
174→          <Closed>
175→            <Body type="span">This restaurant is closed.</Body>
176→          </Closed>
177→        )}
178→        <RestaurantImage $isClosed={isClosed} loading="lazy" src={photoUrl} alt="restaurant" />
179→      </ImageContainer>
180→      <StyledContent>
181→        <StyledHeading level={2}>{name}</StyledHeading>
182→        <Review rating={rating} />
183→        <Description fontWeight="regular">{specialty}</Description>
184→        {categories?.map((category) => <StyledBadge key={category} text={category} />)}
185→      </StyledContent>
186→    </Container>
187→  )
188→}
