15→const Container = styled.div(
16→  ({ theme: { color, spacing, boxShadow, typography, borderRadius } }) => css`
17→    display: flex;
18→    flex-direction: column-reverse;
19→    padding-bottom: ${spacing.m};
20→    label {
21→      color: ${color.label};
22→      font-size: ${typography.fontSize.body};
23→      padding-bottom: ${spacing.xs};
24→      &:first-letter {
25→        text-transform: uppercase;
26→      }
27→    }
28→
29→    select {
