38→      appearance: none;
39→      background-size: 1.5rem;
40→
41→      margin: 0;
42→      &:focus {
43→        box-shadow: ${boxShadow.outerBorder};
44→      }
45→    }
46→
47→    select:focus + label {
48→      color: ${color.labelActive};
49→    }
50→  `
51→)
52→
53→type SelectProps = {
54→  label?: string
55→  options: any[]
56→  value?: any
57→  onChange?: (data: any) => void
58→} & DetailedHTMLProps<SelectHTMLAttributes<HTMLSelectElement>, HTMLSelectElement>
59→
60→export const Select = ({
61→  label = '',
62→  value = '',
63→  options = [],
64→  onChange,
65→  id,
66→  ...otherProps
67→}: SelectProps) => (
68→  <Container>
69→    <select
70→      id={id}
71→      value={value}
72→      onChange={(evt: any) => onChange && onChange(Number(evt.target.value))}
73→      {...otherProps}
74→    >
75→      {options.map((option) => (
76→        <option key={option} value={option}>
77→          {option}
78→        </option>
